mapper.select:
/* SQL ID : MutEvalRltnDAO.selectMutEvalRltn 설 명 : 평가 연결 조회 */ SELECT A.ASMT_MTL_EVL_RSLT_ID AS evalCd , A.EVAL_DIV_CD AS evalDivCd , A.LINK_CD AS rltnCd , A.SBJCT_ID AS crsCreCd FROM TB_LMS_MUT_EVAL_RLTN AS A WHERE 1 = 1
AND A.EVAL_DIV_CD = #{evalDivCd}
AND A.LINK_CD = #{rltnCd}
AND A.SBJCT_ID = #{crsCreCd}

mapper.insert:
		/*
             SQL ID : MutEvalRltnDAO.insertMutEvalRltn
             	설  명 : 평가 연결 등록
        */
        INSERT INTO TB_LMS_MUT_EVAL_RLTN (
        	  ASMT_MTL_EVL_RSLT_ID
			, EVAL_DIV_CD
			, LINK_CD
			, SBJCT_ID
        ) VALUES (
        	  #{evalCd}
        	, #{evalDivCd}
        	, #{rltnCd}
        	, #{crsCreCd}
        )

mapper.delete:
		/*
             SQL ID : MutEvalRltnDAO.delMutEvalRltn
             	설  명 : 평가 연결 삭제
        */
        DELETE FROM TB_LMS_MUT_EVAL_RLTN
         WHERE ASMT_MTL_EVL_RSLT_ID = #{evalCd}

		/*
             SQL ID : MutEvalRltnDAO.delMutEvalRltnByRltnCd
             	설  명 : 평가 연결 삭제
        */
        DELETE FROM TB_LMS_MUT_EVAL_RLTN
         WHERE LINK_CD = #{rltnCd}
